    <Box sx={{ p: 4 }}>
      <Typography variant="h3" gutterBottom>
        Map
      </Typography>
      <Typography>
        Explore opportunities on the map here. (Coming soon)
      </Typography>
    </Box>
  );
}

export default Map;
